+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; size: number}
+	| {type: 'fraction'; fraction: number; min: number}
+	| {type: 'auto'; min: number; max?: number};
+
+type Placement = {
+	column: number;
+	columnSpan: number;
+	row: number;
+	rowSpan: number;
+	child: DOMElement;
+};
+
+const trackPattern = /minmax\\(\\s*(\\d+(?:\\.\\d+)?)\\s*,\\s*(?:(\\d+(?:\\.\\d+)?)fr|(\\d+(?:\\.\\d+)?))\\s*\\)|(\\d+(?:\\.\\d+)?)fr|auto|\\d+(?:\\.\\d+)?/g;
+
+const parseTracks = (template: string | undefined): Track[] => {
+	if (!template) {
+		return [];
+	}
+
+	const tracks: Track[] = [];
+	for (const match of template.matchAll(trackPattern)) {
+		if (match[1]) {
+			const min = Number(match[1]);
+			tracks.push(
+				match[2]
+					? {type: 'fraction', fraction: Number(match[2]), min}
+					: {type: 'auto', min, max: Number(match[3])},
+			);
+		} else if (match[4]) {
+			tracks.push({type: 'fraction', fraction: Number(match[4]), min: 0});
+		} else if (match[0] === 'auto') {
+			tracks.push({type: 'auto', min: 0});
+		} else {
+			tracks.push({type: 'fixed', size: Number(match[0])});
+		}
+	}
+
+	return tracks;
+};
+
+const parsePlacement = (value: number | string | undefined) => {
+	if (typeof value === 'number') {
+		return {start: value - 1, span: 1};
+	}
+
+	if (!value) {
+		return undefined;
+	}
+
+	const [startText, endText] = value.split('/').map(part => part.trim());
+	const start = Number(startText);
+	const end = endText ? Number(endText) : undefined;
+	if (!Number.isInteger(start) || start < 1) {
+		return undefined;
+	}
+
+	return {
+		start: start - 1,
+		span: end && Number.isInteger(end) && end > start ? end - start : 1,
+	};
+};
+
+const resolveTracks = (
+	tracks: Track[],
+	available: number,
+	contentSizes: number[],
+): number[] => {
+	const sizes = tracks.map((track, index) => {
+		if (track.type === 'fixed') {
+			return track.size;
+		}
+
+		if (track.type === 'fraction') {
+			return track.min;
+		}
+
+		const contentSize = contentSizes[index] ?? 0;
+		return Math.max(track.min, track.max === undefined ? contentSize : Math.min(contentSize, track.max));
+	});
+	const remaining = Math.max(0, available - sizes.reduce((total, size) => total + size, 0));
+	const fractionTotal = tracks.reduce(
+		(total, track) => total + (track.type === 'fraction' ? track.fraction : 0),
+		0,
+	);
+
+	if (fractionTotal > 0) {
+		for (const [index, track] of tracks.entries()) {
+			if (track.type === 'fraction') {
+				sizes[index] += (remaining * track.fraction) / fractionTotal;
+			}
+		}
+	}
+
+	return sizes;
+};
+
+const createPlacements = (node: DOMElement, columnCount: number): Placement[] => {
+	const occupied = new Set<string>();
+	const placements: Placement[] = [];
+	const fits = (column: number, row: number, columnSpan: number, rowSpan: number) => {
+		if (column + columnSpan > columnCount) {
+			return false;
+		}
+
+		for (let y = row; y < row + rowSpan; y++) {
+			for (let x = column; x < column + columnSpan; x++) {
+				if (occupied.has(`${x}:${y}`)) {
+					return false;
+				}
+			}
+		}
+
+		return true;
+	};
+
+	for (const child of node.childNodes) {
+		if (!child.yogaNode || child.style.display === 'none') {
+			continue;
+		}
+
+		const columnPlacement = parsePlacement(child.style.gridColumn);
+		const rowPlacement = parsePlacement(child.style.gridRow);
+		const columnSpan = columnPlacement?.span ?? 1;
+		const rowSpan = rowPlacement?.span ?? 1;
+		let column = columnPlacement?.start ?? 0;
+		let row = rowPlacement?.start ?? 0;
+
+		if (!columnPlacement || !rowPlacement) {
+			let found = false;
+			for (let candidateRow = rowPlacement?.start ?? 0; !found; candidateRow++) {
+				for (let candidateColumn = columnPlacement?.start ?? 0; candidateColumn < columnCount; candidateColumn++) {
+					if (fits(candidateColumn, candidateRow, columnSpan, rowSpan)) {
+						column = candidateColumn;
+						row = candidateRow;
+						found = true;
+						break;
+					}
+				}
+			}
+		}
+
+		for (let y = row; y < row + rowSpan; y++) {
+			for (let x = column; x < column + columnSpan; x++) {
+				occupied.add(`${x}:${y}`);
+			}
+		}
+
+		placements.push({column, columnSpan, row, rowSpan, child});
+	}
+
+	return placements;
+};
+
+const layoutGrid = (node: DOMElement): void => {
+	const yogaNode = node.yogaNode!;
+	const columnTracks = parseTracks(node.style.gridTemplateColumns);
+	if (columnTracks.length === 0) {
+		columnTracks.push({type: 'auto', min: 0});
+	}
+
+	const placements = createPlacements(node, columnTracks.length);
+	const rowTracks = parseTracks(node.style.gridTemplateRows);
+	const rowCount = Math.max(rowTracks.length, ...placements.map(placement => placement.row + placement.rowSpan), 1);
+	while (rowTracks.length < rowCount) {
+		rowTracks.push({type: 'auto', min: 0});
+	}
+
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const contentWidth = Math.max(0, yogaNode.getComputedWidth() - yogaNode.getComputedPadding(Yoga.EDGE_LEFT) - yogaNode.getComputedPadding(Yoga.EDGE_RIGHT) - yogaNode.getComputedBorder(Yoga.EDGE_LEFT) - yogaNode.getComputedBorder(Yoga.EDGE_RIGHT));
+	const contentHeight = Math.max(0, yogaNode.getComputedHeight() - yogaNode.getComputedPadding(Yoga.EDGE_TOP) - yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) - yogaNode.getComputedBorder(Yoga.EDGE_TOP) - yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM));
+	const columnContent = Array<number>(columnTracks.length).fill(0);
+	const rowContent = Array<number>(rowTracks.length).fill(0);
+
+	for (const placement of placements) {
+		if (placement.columnSpan === 1) {
+			columnContent[placement.column] = Math.max(columnContent[placement.column], placement.child.yogaNode!.getComputedWidth());
+		}
+
+		if (placement.rowSpan === 1) {
+			rowContent[placement.row] = Math.max(rowContent[placement.row], placement.child.yogaNode!.getComputedHeight());
+		}
+	}
+
+	const columns = resolveTracks(columnTracks, contentWidth - columnGap * (columnTracks.length - 1), columnContent);
+	const rows = resolveTracks(rowTracks, contentHeight - rowGap * (rowTracks.length - 1), rowContent);
+	const x = columns.reduce<number[]>((positions, size) => [...positions, (positions.at(-1) ?? 0) + size + columnGap], [0]);
+	const y = rows.reduce<number[]>((positions, size) => [...positions, (positions.at(-1) ?? 0) + size + rowGap], [0]);
+
+	for (const placement of placements) {
+		const width = columns.slice(placement.column, placement.column + placement.columnSpan).reduce((total, size) => total + size, 0) + columnGap * (placement.columnSpan - 1);
+		const height = rows.slice(placement.row, placement.row + placement.rowSpan).reduce((total, size) => total + size, 0) + rowGap * (placement.rowSpan - 1);
+		const child = placement.child.yogaNode!;
+		child.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		child.setPosition(Yoga.EDGE_LEFT, x[placement.column]);
+		child.setPosition(Yoga.EDGE_TOP, y[placement.row]);
+		child.setWidth(width);
+		child.setHeight(height);
+	}
+
+	if (node.style.height === undefined) {
+		yogaNode.setHeight(rows.reduce((total, size) => total + size, 0) + rowGap * (rows.length - 1) + yogaNode.getComputedPadding(Yoga.EDGE_TOP) + yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) + yogaNode.getComputedBorder(Yoga.EDGE_TOP) + yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM));
+	}
+};
+
+/** Applies Ink's grid subset after Yoga has measured the normal document flow. */
+export const applyGridLayout = (node: DOMElement): void => {
+	if (node.style.display === 'grid' && node.yogaNode) {
+		layoutGrid(node);
+	}
+
+	for (const child of node.childNodes) {
+		if (child.nodeName !== '#text') {
+			applyGridLayout(child);
+		}
+	}
+};
